import{c as t,Q as o,j as d,m as a}from"./chunks/framework.DVP2LVsd.js";const p=JSON.parse('{"title":"Embed API","description":"","frontmatter":{},"headers":[],"relativePath":"api/integrations/embed-api.md","filePath":"api/integrations/embed-api.md","lastUpdated":1781370958000}'),i={name:"api/integrations/embed-api.md"};function r(n,e,s,l,c,h){return o(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="embed-api" tabindex="-1">Embed API <a class="header-anchor" href="#embed-api" aria-label="Permalink to &quot;Embed API&quot;">​</a></h1><p>LibrisLog provides an <strong>embed API</strong> that returns a self-contained HTML page with your reading statistics. It is designed for iframe widgets in dashboards that cannot set custom HTTP headers (Homarr, Homepage, etc.).</p><p>The embed endpoint (<code>/embed/v1/stats</code>) renders your stats as styled stat cards with inline CSS, no JavaScript, and no external dependencies.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>A running LibrisLog instance reachable from your dashboard server</li><li>An <strong>embed token</strong> with access to the embed widget endpoint</li><li>Embed endpoints must be enabled (default: enabled). To disable, set <code>EMBED_ENABLED=false</code> in your environment.</li></ul><h2 id="creating-an-embed-token" tabindex="-1">Creating an Embed Token <a class="header-anchor" href="#creating-an-embed-token" aria-label="Permalink to &quot;Creating an Embed Token&quot;">​</a></h2><ol><li>Go to your LibrisLog <a href="/next/guide/using-librislog/profile.html">Profile</a> page.</li><li>Scroll to the <strong>Embed Tokens</strong> section.</li><li>Enter a name for your widget (e.g. &quot;My Dashboard&quot;).</li><li>Optionally limit allowed origins for security. Leave empty (wildcard) or set to your dashboard&#39;s URL.</li><li>Optionally set an expiry date for the token.</li><li>Click <strong>Add token</strong>.</li><li><strong>Copy the displayed token immediately</strong> — it is shown only once.</li></ol><h2 id="endpoint" tabindex="-1">Endpoint <a class="header-anchor" href="#endpoint" aria-label="Permalink to &quot;Endpoint&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /embed/v1/stats?token=&lt;EMBED-TOKEN&gt;</span></span></code></pre></div><p>The token is passed as a query parameter. No <code>X-API-Key</code> header or browser session is required, making it ideal for iframes.</p><h3 id="customizing-the-look" tabindex="-1">Customizing the Look <a class="header-anchor" href="#customizing-the-look" aria-label="Permalink to &quot;Customizing the Look&quot;">​</a></h3><p>Optional query parameters to style the widget:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Default</th><th>Values</th><th>Description</th></tr></thead><tbody><tr><td><code>theme</code></td><td><code>light</code></td><td><code>light</code>, <code>dark</code></td><td>Color theme</td></tr><tr><td><code>accent</code></td><td><code>#3b82f6</code></td><td>hex color</td><td>Accent color for stat numbers</td></tr><tr><td><code>radius</code></td><td><code>md</code></td><td><code>none</code>, <code>sm</code>, <code>md</code>, <code>lg</code>, <code>xl</code></td><td>Card border radius</td></tr><tr><td><code>density</code></td><td><code>normal</code></td><td><code>compact</code>, <code>normal</code>, <code>comfortable</code></td><td>Spacing between stat cards</td></tr><tr><td><code>hide_labels</code></td><td><code>false</code></td><td><code>true</code>, <code>false</code></td><td>Hide text labels</td></tr><tr><td><code>show</code></td><td>all stats</td><td><code>books</code>, <code>reading</code>, <code>read</code>, <code>to_read</code>, <code>pages</code>, <code>avg_pages</code></td><td>Comma-separated list of stat keys to display</td></tr><tr><td><code>lang</code></td><td><code>en</code></td><td>any language code</td><td>HTML <code>lang</code> attribute; translates stat labels when a matching locale is available</td></tr><tr><td><code>font_scale</code></td><td><code>1.0</code></td><td><code>0.5</code>–<code>3.0</code></td><td>Font size multiplier</td></tr><tr><td><code>layout</code></td><td><code>grid</code></td><td><code>grid</code>, <code>list</code></td><td>Layout mode</td></tr></tbody></table><p>Example with custom styling:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;LIBRISLOG-URL&gt;/embed/v1/stats?token=&lt;EMBED-TOKEN&gt;&amp;theme=dark&amp;accent=%23f59e0b&amp;radius=sm&amp;density=compact&amp;hide_labels=true</span></span></code></pre></div><blockquote><p><strong>Note:</strong> The accent color must be URL-encoded (e.g. <code>%23</code> for <code>#</code>).</p></blockquote><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>The embed endpoint returns a minimal, self-contained HTML page with your reading statistics. It includes:</p><ul><li>Inline CSS (no external dependencies)</li><li>No-referrer policy and security headers</li><li>No JavaScript, no app shell, no auth redirects</li></ul><p>Authentication is handled via the embed token in the query string.</p><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><ul><li>Embed tokens are scoped to <code>embed:stats:read</code> only — they cannot access any other API endpoint.</li><li>Tokens can be revoked or rotated individually from your Profile page.</li><li>If configured, origin restrictions prevent token reuse on unauthorized dashboards.</li><li>The embed response does not include the token in the rendered HTML body.</li><li>Response headers include: <ul><li><code>Cache-Control: private, max-age=60</code></li><li><code>X-Content-Type-Options: nosniff</code></li><li><code>Referrer-Policy: no-referrer</code></li><li><code>Content-Security-Policy: default-src &#39;none&#39;; style-src &#39;unsafe-inline&#39;; frame-ancestors *</code></li></ul></li><li>The embed endpoint can be fully disabled by setting <code>EMBED_ENABLED=false</code>.</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p><strong>Widget shows &quot;Invalid or revoked token&quot;</strong></p><ul><li>Verify the token was not revoked or rotated.</li><li>Check that the token has not expired.</li><li>Ensure <code>EMBED_ENABLED</code> is not set to <code>false</code> in your environment.</li></ul><p><strong>Widget returns 403 Forbidden</strong></p><ul><li>If you configured allowed origins on your token, ensure the <code>Origin</code> header sent by your dashboard matches one of the listed origins.</li><li>Try removing the allowed origins restriction (set to empty/wildcard) for testing.</li></ul><p><strong>Stats are empty (all zeros)</strong></p><ul><li>The widget displays statistics for the token owner&#39;s account. Ensure you have added books to your LibrisLog library.</li></ul><p><strong>CSP errors in browser console</strong></p><ul><li>The embed endpoint sets a <code>Content-Security-Policy</code> header optimized for its minimal HTML. If your dashboard adds a CSP of its own, you may need to adjust it to allow inline styles from the iframe.</li></ul>',31)])])}const m=t(i,[["render",r]]);export{p as __pageData,m as default};
